package com.oceandatum.quality.common.rulebase;
import org.apache.commons.lang3.StringUtils;

/**
 * 字符串全角检查
 * @author sxj
 * @create 2021-07-20 11:30
 */
public class FullAngleRule extends AbstractRule {

    @Override
    public boolean doCheck(String value) {
        return this.doFullAngleCheck(value);
    }

    @Override
    public boolean doCheck(String value, String target) {
        return false;
    }

    public boolean doFullAngleCheck(String value){
        if (StringUtils.isBlank(value)){
            return false;
        }
        boolean result = false;
        // 首先将汉字用空格替换掉
        value = value.replaceAll("[\u4e00-\u9fa5]", "");

        char[] chars_test3 = value.toCharArray();
        for (int i = 0; i < chars_test3.length; i++) {
            int charValue = (int) chars_test3[i];
            // 判断是全角字符
            if (charValue >= 65281 && charValue <= 65374 || charValue == 12288) {
                result = true;
                break;
            }
//            // 判断是半角字符
//            else if (charValue >= 33 && charValue <= 126 || charValue == 32) {
//                System.out.println("半角  " + (char) charValue);
//            }
//            else{
//                System.out.println("其他  " + (char) charValue);
//            }
        }
        return result;
    }
}
